arguments.file_text:
@using sv_564ee75be8744792a75bc3464951fd37.Services

<div class="message-list" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }

    @foreach (var msg in Messages)
    {
        var threadInfo = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == msg.Id);
        <MessageBubble Message="msg"
                       IsThreadStarter="@(threadInfo is not null)"
                       ReplyCount="@(threadInfo?.ReplyCount ?? 0)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top detection is handled via JS interop in the page
        // This provides a fallback mechanism
        await Task.CompletedTask;
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 2px;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

@using sv_564ee75be8744792a75bc3464951fd37.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <MessageBubble Message="reply"
                           IsThreadStarter="false"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

