arguments.file_text:
@page "/chat"
@using sv_564ee75be8744792a75bc3464951fd37.Services
@using sv_564ee75be8744792a75bc3464951fd37.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="@(selectedChannel?.Id ?? 0)"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadOpen ? "" : "chat-main-full")">
        @if (selectedChannel is not null)
        {
            <div class="main-header">
                <h5># @selectedChannel.Name</h5>
                <span class="main-description">@selectedChannel.Description</span>
            </div>

            <div class="main-messages" id="message-scroll-container" @onscroll="HandleScroll">
                @if (isLoadingMore)
                {
                    <div class="loading-more">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    var threadInfo = threadSummaries.FirstOrDefault(t => t.RootMessageId == msg.Id);
                    <MessageBubble Message="msg"
                                   IsThreadStarter="@(threadInfo is not null)"
                                   ReplyCount="@(threadInfo?.ReplyCount ?? 0)"
                                   OnOpenThread="OpenThread"
                                   OnReact="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="Message #@selectedChannel.Name"
                          ButtonLabel="Send"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen && threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private Channel? selectedChannel;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        messages = [];
        threadSummaries = [];
        hasMoreMessages = true;
        CloseThreadInternal();

        await ChatService.MarkChannelReadAsync(channel.Id);

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        BuildThreadSummaries();
        RefreshChannelUnread(channel.Id);
    }

