    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadInternal();
    }

    private void CloseThreadInternal()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        UpdateThreadSummary(threadRootMessage.Id);
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Optimistic update in the messages list
        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId)
                  ?? threadReplies.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        threadSummaries = replies
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }

    private void UpdateThreadSummary(int rootMessageId)
    {
        var existing = threadSummaries.FirstOrDefault(t => t.RootMessageId == rootMessageId);
        if (existing is not null)
        {
            threadSummaries.Remove(existing);
        }
        threadSummaries.Add(new ThreadSummary(rootMessageId, threadReplies.Count, DateTime.UtcNow));
    }

    private void RefreshChannelUnread(int channelId)
    {
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }
